class Node {
  constructor(c){
    this.x = random(width);
    this.y = random(height);
    this.xSpeed = random(-1.5, 1.5);
    this.ySpeed = random(-1.5, 1.5);
    this.color = c;
  }

  move() {
    if (this.x < 0 || this.x > width) {
      this.xSpeed *= -1;
    }
    this.x += this.xSpeed;
    if (this.y < 0 || this.y > height) {
      this.ySpeed *= -1;
    }
    this.y += this.ySpeed;
  }
}

drawLines(nodes) {
  for (let n of nodes) {
    let d = dist(this.x, this.y, n.x, n.y);
    if (d < 70 && d > 2) {
      stroke(this.color);
      line(this.x, this.y, n.x, n.y);
    }
  }
}
